function Frequency
   (CID      : Countable_Clock_Id;
    Rounded  : Boolean := True;
    Accuracy : UInt4 := 15)
    return Hertz

procedure Initialize
   (XOSC_Frequency     : XOSC_Hertz := 0;
    XOSC_Startup_Delay : XOSC_Cycles := 770_048;
    SYS_PLL_Config     : PLL_Config := PLL_125_MHz)
